/**
 * Material Design 3 Theme - Search Worker
 * Handles search indexing and querying using lunr.js
 * Loaded as a Web Worker for non-blocking search
 */

// lunr.js will be imported via importScripts
let lunrIndex = null;
let documents = {};

// Import lunr.js from CDN
importScripts('https://cdn.jsdelivr.net/npm/lunr@2.3.9/lunr.min.js');

// Listen for messages from main thread
self.onmessage = function(e) {
  const data = e.data;

  if (data.init) {
    initIndex(data.init.lunrLanguages || []);
  }

  if (data.q) {
    if (lunrIndex) {
      const results = search(data.q);
      self.postMessage({ e: 'query-ready', d: results });
    }
  }
};

async function initIndex(lunrLanguages) {
  try {
    // Fetch the index.json file
    const res = await fetch('../index.json');
    if (!res.ok) {
      throw new Error('Failed to fetch index.json: ' + res.status);
    }

    const data = await res.json();
    documents = data;

    // Build lunr index
    lunrIndex = lunr(function() {
      this.ref('href');
      this.field('title', { boost: 50 });
      this.field('keywords', { boost: 40 });
      this.field('summary', { boost: 20 });

      // Tokenizer separator
      lunr.tokenizer.separator = /[\s\-.()]+/;

      // Add all documents
      for (const key in data) {
        this.add(data[key]);
      }
    });

    self.postMessage({ e: 'index-ready' });
  } catch (error) {
    console.error('Failed to initialize search index:', error);
    self.postMessage({ e: 'index-error', error: error.message });
  }
}

function search(query) {
  if (!lunrIndex) return [];

  try {
    // Preprocess query: add + prefix for required terms
    const additiveQuery = query.replace(/\s+/g, ' ').split(' ')
      .map(w => w.trim())
      .filter(w => w.length > 0)
      .map(w => '+' + w)
      .join(' ');

    const results = lunrIndex.search(additiveQuery);

    return results.map(result => {
      const doc = documents[result.ref];
      if (doc) {
        return {
          href: doc.href,
          title: doc.title,
          summary: doc.summary || '',
          keywords: doc.keywords || ''
        };
      }
      return null;
    }).filter(Boolean);
  } catch (e) {
    console.error('Search error:', e);
    return [];
  }
}
